    //final boolean ifProd= License.isProd();
    final RagicBundle bundle = (RagicBundle) session.getAttribute("RAGIC_BUNDLE");
    final NUIForm form = AppManager.getFormPage(apname, path, sheetIndex);
    final int rootDomainId = form.getRootDomainId();
    final boolean addParentEntryManager = form.ifAddParentEntryManager();
    final Account account = Account.getInstance(apname);
    final String cacheSignature = "ENTRY_MANAGER_REASSIGN_" + apname;
    final SystemCache systemCache = SystemCache.getInstance();
    if (systemCache.get(cacheSignature) != null) return;

    final User user = (User) session.getAttribute("USER");
    if (user == null || !user.ifApManager(apname, path)) return;
    systemCache.put(cacheSignature, user.getUserName(apname));


    Thread t = new Thread(new Runnable() {
        public void run() {
            SystemTaskProgress.setStatus(apname, Const.STP_MASSEDIT, "Initializing...", 0, SystemTaskProgress.Status.PROCESSING);

            //Register running service
            EntryManagerReAssignRunningService rs = new EntryManagerReAssignRunningService(form.getUrl());
            LongTermTask ltt= ThreadManager.getInstance().addTask(Thread.currentThread(),apname,"Guest user reassign:"+form.getUrl());
            RunningServiceRegister.getInstance().addService(apname, rs);

            //Find parent forms if any
            //Set<Integer> parentFormRootDomainIds = account.getParentFormRootDomainIds(rootDomainId);

            List<CellInfo> assignFields = new ArrayList<>();
            //List<CellInfo> linkToParentFields = new ArrayList<>();
            Map<CellLocation, CellInfo> formFields = form.getFields();
            for (Map.Entry<CellLocation, CellInfo> e : formFields.entrySet()) {
                CellInfo info = e.getValue();
                if (info.getAttribute("em")!=null) {
                    assignFields.add(info);
                }

//                if (parentFormRootDomainIds != null
//                        && (parentFormRootDomainIds.contains(info.getDomainId())
//                        || parentFormRootDomainIds.contains(Encoder.parseInt(info.getAttribute("s"))) )
//                ) {
//                    linkToParentFields.add(info);
//                }
            }


            List<BDBWorkerCommand> unlinkCommands = new ArrayList<>();
            List<BDBWorkerCommand> linkCommands = new ArrayList<>();
            Map<Integer, Set<String>> assignedUsersMap = new HashMap<>();
            BDBWorker worker = new BDBWorker(apname);

            try { // try catch ensure every threads release right when they end(whether by exception or anything else)

                SystemTaskProgress.setStatus(apname, Const.STP_MASSEDIT, "Start reapplying guest user...", 0, SystemTaskProgress.Status.PROCESSING);

                SDBQuery q = new SDBQueryFull(worker);
                SDBNode keyNode, node;

                q.go(rootDomainId);
                while ((keyNode = q.next()) != null){
                    int keyNodeId = keyNode.getId();
                    List<SDBNode> allNodes = q.dipAllNodes(DConst.ENTRY_GUEST_USER);
                    for (SDBNode n : allNodes) {
                        unlinkCommands.add(new BDBWorkerCommandUnlink(rootDomainId, keyNode.getId(), DConst.ENTRY_GUEST_USER, n.getId()));
                    }

                    //Find all values in assign fields, which should be added to entry manager
                    Set<String> assignedUsers = new HashSet<>();
                    String value;
                    for (CellInfo info : assignFields) {
                        int domainId = info.getDomainId();
                        assignedUsers.add(q.dip(domainId));
                    }

                    assignedUsersMap.put(keyNodeId, assignedUsers);

                }


            } catch (Exception e) {
            } finally {
                worker.commit();
            }

            //unlink
            worker = new BDBWorker(apname);
            int count = 0;
            try{
                for (BDBWorkerCommand c : unlinkCommands) {
                    c.execute(worker);
                    //SystemTaskProgress.setStatus(apname, "Deleted", ++count, false);
                }
            } catch (Exception e) {
            } finally {
                worker.commit();
            }

            //addnode + linknode
            worker = new BDBWorker(apname);
            count = 0;
            try{
                for (Map.Entry<Integer, Set<String>> mapEntry : assignedUsersMap.entrySet()) {
                    int keyNodeId = mapEntry.getKey();
                    Set<String> emails = mapEntry.getValue();
                    for (String email : emails) {
                        int nodeId = worker.addNode(DConst.ENTRY_GUEST_USER, email, true);
                        worker.linkNode(rootDomainId, keyNodeId, DConst.ENTRY_GUEST_USER, nodeId);
                    }
                    SystemTaskProgress.setStatus(apname, Const.STP_MASSEDIT, "Assigned guest", ++count, SystemTaskProgress.Status.PROCESSING);
                }

                for (BDBWorkerCommand c : linkCommands) {
                    c.execute(worker);
                }
            } catch (Exception e) {
            } finally {
                worker.commit();
                RunningServiceRegister.getInstance().removeService(apname, rs);
                ThreadManager.getInstance().removeTask(ltt);
                systemCache.remove(cacheSignature);
                SystemTaskProgress.setStatus(apname, Const.STP_MASSEDIT, "Reassign guest complete!", -1, SystemTaskProgress.Status.DONE);
            }
        }
    });
    t.setName("Reassign guest:" + apname + path + "/" + sheetIndex + " " + user.getUserId());
    t.start();

